 42→interface RouteHandle<TParams, TQuery, TBody> {
 43→  /** Check if this route matches the request */
 44→  match(method: string | undefined, pathSegments: string[]): boolean;
 45→
 46→  /** Parse + validate params, query, body. Returns null and sends 400 on validation failure. */
 47→  parse(
 48→    req: IncomingMessage,
 49→    res: ServerResponse,
 50→    pathSegments: string[],
 51→    queryParams: URLSearchParams,
 52→  ): Promise<ParsedRequest<TParams, TQuery, TBody> | null>;
 53→
 54→  /** The raw definition (for OpenAPI generation) */
 55→  def: RouteDef;
 56→}
 57→
 58→// ─── Registry ────────────────────────────────────────────────────────────────
 59→
 60→/** Global registry — populated at import time, read by OpenAPI generator */
 61→export const routeRegistry: RouteDef[] = [];
 62→
 63→// ─── Factory ─────────────────────────────────────────────────────────────────
 64→
 65→export function route<
 66→  TParams extends z.ZodType = z.ZodUndefined,
 67→  TQuery extends z.ZodType = z.ZodUndefined,
 68→  TBody extends z.ZodType = z.ZodUndefined,
 69→>(
 70→  def: RouteDef<TParams, TQuery, TBody>,
 71→): RouteHandle<z.infer<TParams>, z.infer<TQuery>, z.infer<TBody>> {
 72→  routeRegistry.push(def as RouteDef);
 73→
 74→  return {
 75→    def: def as RouteDef,
 76→
 77→    match(method, pathSegments) {
 78→      return matchRoute(
 79→        method,
 80→        pathSegments,
 81→        def.method.toUpperCase(),
 82→        def.pattern,
 83→        def.exact ?? true,
 84→      );
 85→    },
 86→
 87→    async parse(req, res, pathSegments, queryParams) {
 88→      try {
 89→        // Extract path params from dynamic segments
 90→        const rawParams: Record<string, string> = {};
 91→        if (def.params) {
 92→          const paramNames = def.path.match(/\{(\w+)\}/g)?.map((p) => p.slice(1, -1)) ?? [];
 93→          for (let i = 0; i < def.pattern.length; i++) {
 94→            if (def.pattern[i] === null && paramNames.length > 0) {
 95→              rawParams[paramNames.shift()!] = pathSegments[i] ?? "";
 96→            }
 97→          }
 98→        }
 99→
100→        // Parse + validate each part
101→        const params = def.params ? def.params.parse(rawParams) : undefined;
102→        const query = def.query ? def.query.parse(Object.fromEntries(queryParams)) : undefined;
103→        const body = def.body ? def.body.parse(await parseBody(req)) : undefined;
104→
105→        return { params, query, body } as ParsedRequest<
106→          z.infer<TParams>,
107→          z.infer<TQuery>,
108→          z.infer<TBody>
109→        >;
110→      } catch (err) {
111→        if (err instanceof z.ZodError) {
112→          jsonError(
113→            res,
114→            `Validation error: ${err.issues.map((e) => `${e.path.join(".")}: ${e.message}`).join(", ")}`,
115→            400,
116→          );
117→          return null;
118→        }
119→        throw err;
120→      }
121→    },
122→  };
123→}
