  1→/**
  2→ * HTTP handlers for the Linear integration OAuth flow.
  3→ *
  4→ * GET /api/linear/authorize  — Redirect to Linear OAuth consent screen
  5→ * GET /api/linear/callback   — Handle the OAuth callback, exchange code for tokens
  6→ */
  7→import type { IncomingMessage, ServerResponse } from "node:http";
  8→import { getAuthorizationUrl, handleOAuthCallback, isLinearEnabled } from "../linear";
  9→import { route } from "./route-def";
 10→
 11→// ─── Route Definitions ──────────────────────────────────────────────────────
 12→
 13→const linearAuthorize = route({
 14→  method: "get",
 15→  path: "/api/linear/authorize",
 16→  pattern: ["api", "linear", "authorize"],
 17→  summary: "Redirect to Linear OAuth consent screen",
 18→  tags: ["Linear"],
 19→  auth: { apiKey: false },
 20→  responses: {
 21→    302: { description: "Redirect to Linear OAuth" },
 22→    500: { description: "Failed to generate authorization URL" },
 23→    503: { description: "Linear integration not configured" },
 24→  },
 25→});
 26→
 27→const linearCallback = route({
 28→  method: "get",
 29→  path: "/api/linear/callback",
 30→  pattern: ["api", "linear", "callback"],
 31→  summary: "Handle Linear OAuth callback",
 32→  tags: ["Linear"],
 33→  auth: { apiKey: false },
 34→  responses: {
 35→    200: { description: "OAuth authorization complete" },
 36→    400: { description: "Missing or invalid parameters" },
 37→    500: { description: "OAuth callback failed" },
 38→    503: { description: "Linear integration not configured" },
 39→  },
 40→});
 41→
 42→// ─── Handler ────────────────────────────────────────────────────────────────
 43→
 44→export async function handleLinear(
 45→  req: IncomingMessage,
 46→  res: ServerResponse,
 47→  pathSegments: string[],
 48→): Promise<boolean> {
 49→  // ── GET /api/linear/authorize ──
 50→  if (linearAuthorize.match(req.method, pathSegments)) {
 51→    if (!isLinearEnabled()) {
 52→      res.writeHead(503, { "Content-Type": "application/json" });
 53→      res.end(JSON.stringify({ error: "Linear integration not configured" }));
 54→      return true;
 55→    }
 56→
 57→    try {
 58→      const url = await getAuthorizationUrl();
 59→      res.writeHead(302, { Location: url });
 60→      res.end();
 61→    } catch (err) {
 62→      const message = err instanceof Error ? err.message : String(err);
 63→      console.error(`[Linear] Error generating authorization URL: ${message}`);
 64→      res.writeHead(500, { "Content-Type": "application/json" });
 65→      res.end(JSON.stringify({ error: "Failed to generate authorization URL", details: message }));
 66→    }
 67→    return true;
 68→  }
 69→
 70→  // ── GET /api/linear/callback ──
 71→  if (linearCallback.match(req.method, pathSegments)) {
 72→    if (!isLinearEnabled()) {
 73→      res.writeHead(503, { "Content-Type": "application/json" });
 74→      res.end(JSON.stringify({ error: "Linear integration not configured" }));
 75→      return true;
 76→    }
 77→
 78→    // Parse query params from the URL
 79→    const url = new URL(req.url || "", `http://${req.headers.host || "localhost"}`);
 80→    const code = url.searchParams.get("code");
 81→    const state = url.searchParams.get("state");
 82→    const error = url.searchParams.get("error");
 83→
 84→    if (error) {
 85→      console.error(`[Linear] OAuth error: ${error}`);
 86→      res.writeHead(400, { "Content-Type": "application/json" });
 87→      res.end(JSON.stringify({ error: `OAuth denied: ${error}` }));
 88→      return true;
 89→    }
 90→
 91→    if (!code || !state) {
 92→      res.writeHead(400, { "Content-Type": "application/json" });
 93→      res.end(JSON.stringify({ error: "Missing code or state parameter" }));
 94→      return true;
 95→    }
 96→
 97→    try {
 98→      await handleOAuthCallback(code, state);
 99→      res.writeHead(200, { "Content-Type": "text/html" });
100→      res.end(
101→        "<html><body><h1>Linear Connected!</h1><p>OAuth authorization complete. You can close this window.</p></body></html>",
102→      );
103→    } catch (err) {
104→      const message = err instanceof Error ? err.message : String(err);
105→      console.error(`[Linear] OAuth callback error: ${message}`);
106→      res.writeHead(500, { "Content-Type": "application/json" });
107→      res.end(JSON.stringify({ error: "OAuth callback failed", details: message }));
108→    }
109→    return true;
110→  }
111→
112→  return false;
113→}
