189→
190→export async function handleTasks(
191→  req: IncomingMessage,
192→  res: ServerResponse,
193→  pathSegments: string[],
194→  queryParams: URLSearchParams,
195→  myAgentId: string | undefined,
196→): Promise<boolean> {
197→  if (listTasks.match(req.method, pathSegments)) {
198→    const parsed = await listTasks.parse(req, res, pathSegments, queryParams);
199→    if (!parsed) return true;
200→    const filters = {
201→      status: (parsed.query.status as import("../types").AgentTaskStatus) || undefined,
202→      agentId: parsed.query.agentId || undefined,
203→      epicId: parsed.query.epicId || undefined,
204→      scheduleId: parsed.query.scheduleId || undefined,
205→      search: parsed.query.search || undefined,
206→      includeHeartbeat: parsed.query.includeHeartbeat === "true" || undefined,
207→      limit: parsed.query.limit,
208→      offset: parsed.query.offset,
209→    };
210→    const tasks = getAllTasks(filters);
211→    const total = getTasksCount(filters);
212→    json(res, { tasks, total });
213→    return true;
214→  }
215→
216→  if (createTask.match(req.method, pathSegments)) {
217→    const parsed = await createTask.parse(req, res, pathSegments, queryParams);
218→    if (!parsed) return true;
219→
220→    try {
221→      const task = createTaskExtended(parsed.body.task, {
222→        agentId: parsed.body.agentId || undefined,
223→        creatorAgentId: myAgentId || undefined,
224→        taskType: parsed.body.taskType || undefined,
225→        tags: parsed.body.tags || undefined,
226→        priority: parsed.body.priority || 50,
227→        dependsOn: parsed.body.dependsOn || undefined,
228→        offeredTo: parsed.body.offeredTo || undefined,
229→        dir: parsed.body.dir || undefined,
230→        parentTaskId: parsed.body.parentTaskId || undefined,
231→        source: (parsed.body.source as import("../types").AgentTaskSource) || "api",
232→      });
233→      json(res, task, 201);
234→    } catch (error) {
235→      console.error("[HTTP] Failed to create task:", error);
236→      jsonError(res, "Failed to create task", 500);
237→    }
238→    return true;
239→  }
240→
241→  if (updateClaudeSession.match(req.method, pathSegments)) {
242→    const parsed = await updateClaudeSession.parse(req, res, pathSegments, queryParams);
243→    if (!parsed) return true;
244→    const task = updateTaskClaudeSessionId(parsed.params.id, parsed.body.claudeSessionId);
245→    if (!task) {
246→      jsonError(res, "Task not found", 404);
247→      return true;
248→    }
249→    json(res, task);
250→    return true;
251→  }
252→
253→  if (cancelTaskRoute.match(req.method, pathSegments)) {
254→    const parsed = await cancelTaskRoute.parse(req, res, pathSegments, queryParams);
255→    if (!parsed) return true;
256→    const task = getTaskById(parsed.params.id);
257→
258→    if (!task) {
259→      jsonError(res, "Task not found", 404);
260→      return true;
261→    }
262→
263→    const terminalStatuses = ["completed", "failed", "cancelled"];
264→    if (terminalStatuses.includes(task.status)) {
265→      jsonError(res, `Cannot cancel task with status '${task.status}'`, 400);
266→      return true;
267→    }
268→
269→    // Parse optional reason from body (already consumed by parse if body schema exists,
270→    // but cancel has no body schema — read raw)
271→    let reason: string | undefined;
272→    const chunks: Buffer[] = [];
273→    for await (const chunk of req) {
274→      chunks.push(chunk);
275→    }
276→    const raw = Buffer.concat(chunks).toString();
277→    if (raw) {
278→      try {
279→        const body = JSON.parse(raw);
280→        reason = body.reason;
281→      } catch {
282→        // No body or invalid JSON — proceed without reason
283→      }
284→    }
285→
286→    const cancelledTask = cancelTask(parsed.params.id, reason);
287→    if (!cancelledTask) {
288→      jsonError(res, "Failed to cancel task", 500);
289→      return true;
290→    }
291→
292→    if (task.agentId) {
293→      updateAgentStatusFromCapacity(task.agentId);
294→    }
295→
296→    json(res, { success: true, task: cancelledTask });
297→    return true;
298→  }
299→
300→  if (getTask.match(req.method, pathSegments)) {
301→    const parsed = await getTask.parse(req, res, pathSegments, queryParams);
302→    if (!parsed) return true;
303→    const task = getTaskById(parsed.params.id);
304→
305→    if (!task) {
306→      jsonError(res, "Task not found", 404);
307→      return true;
308→    }
309→
310→    const logs = getLogsByTaskId(parsed.params.id);
311→    json(res, { ...task, logs });
312→    return true;
313→  }
314→
315→  if (updateTaskProgressRoute.match(req.method, pathSegments)) {
316→    const parsed = await updateTaskProgressRoute.parse(req, res, pathSegments, queryParams);
317→    if (!parsed) return true;
318→    const task = getTaskById(parsed.params.id);
319→
320→    if (!task) {
321→      jsonError(res, "Task not found", 404);
322→      return true;
323→    }
324→
325→    updateTaskProgress(parsed.params.id, parsed.body.progress);
326→    json(res, { success: true });
327→    return true;
328→  }
329→
330→  if (finishTask.match(req.method, pathSegments)) {
331→    if (!myAgentId) {
332→      jsonError(res, "Missing X-Agent-ID header", 400);
333→      return true;
334→    }
335→
336→    const parsed = await finishTask.parse(req, res, pathSegments, queryParams);
337→    if (!parsed) return true;
338→
339→    const result = getDb().transaction(() => {
340→      const task = getTaskById(parsed.params.id);
341→
342→      if (!task) {
343→        return { error: "Task not found", status: 404 };
344→      }
345→
346→      if (task.agentId && task.agentId !== myAgentId) {
347→        return { error: "Task is assigned to another agent", status: 403 };
348→      }
349→
350→      if (task.status !== "in_progress") {
351→        return { task, alreadyFinished: true };
352→      }
353→
354→      let updatedTask: typeof task;
355→      if (parsed.body.status === "completed") {
356→        const result = completeTask(
357→          parsed.params.id,
358→          parsed.body.output || "Completed by runner wrapper (no explicit output)",
359→        );
360→        if (!result) {
361→          return { error: "Failed to complete task", status: 500 };
362→        }
363→        updatedTask = result;
364→      } else {
365→        const result = failTask(
366→          parsed.params.id,
367→          parsed.body.failureReason || "Process exited without explicit completion",
368→        );
369→        if (!result) {
370→          return { error: "Failed to mark task as failed", status: 500 };
371→        }
372→        updatedTask = result;
373→      }
374→
375→      if (task.agentId) {
376→        updateAgentStatusFromCapacity(task.agentId);
377→      }
378→
379→      return { task: updatedTask };
380→    })();
381→
382→    if ("error" in result && result.error) {
383→      jsonError(res, result.error, (result as { status?: number }).status ?? 500);
384→      return true;
385→    }
386→
387→    json(res, {
388→      success: true,
389→      alreadyFinished: "alreadyFinished" in result ? result.alreadyFinished : false,
390→      task: result.task,
391→    });
392→    return true;
393→  }
394→
395→  if (listPausedTasks.match(req.method, pathSegments)) {
396→    if (!myAgentId) {
397→      jsonError(res, "Missing X-Agent-ID header", 400);
398→      return true;
399→    }
400→    const pausedTasks = getPausedTasksForAgent(myAgentId);
401→    json(res, { tasks: pausedTasks });
402→    return true;
403→  }
404→
405→  if (pauseTaskRoute.match(req.method, pathSegments)) {
406→    const parsed = await pauseTaskRoute.parse(req, res, pathSegments, queryParams);
407→    if (!parsed) return true;
408→    const task = getTaskById(parsed.params.id);
409→
410→    if (!task) {
411→      jsonError(res, "Task not found", 404);
412→      return true;
413→    }
414→
415→    if (myAgentId && task.agentId !== myAgentId) {
416→      jsonError(res, "Task belongs to another agent", 403);
417→      return true;
418→    }
419→
420→    if (task.status !== "in_progress") {
421→      jsonError(res, `Task status is '${task.status}', not 'in_progress'`, 400);
422→      return true;
423→    }
424→
425→    const pausedTask = pauseTask(parsed.params.id);
426→    if (!pausedTask) {
427→      jsonError(res, "Failed to pause task", 500);
428→      return true;
429→    }
430→
431→    json(res, { success: true, task: pausedTask });
432→    return true;
433→  }
434→
435→  if (resumeTaskRoute.match(req.method, pathSegments)) {
436→    const parsed = await resumeTaskRoute.parse(req, res, pathSegments, queryParams);
437→    if (!parsed) return true;
438→    const task = getTaskById(parsed.params.id);
439→
440→    if (!task) {
441→      jsonError(res, "Task not found", 404);
442→      return true;
443→    }
444→
445→    if (myAgentId && task.agentId !== myAgentId) {
446→      jsonError(res, "Task belongs to another agent", 403);
447→      return true;
448→    }
449→
450→    if (task.status !== "paused") {
451→      jsonError(res, `Task status is '${task.status}', not 'paused'`, 400);
452→      return true;
453→    }
454→
455→    const resumedTask = resumeTask(parsed.params.id);
456→    if (!resumedTask) {
457→      jsonError(res, "Failed to resume task", 500);
458→      return true;
459→    }
460→
461→    json(res, { success: true, task: resumedTask });
462→    return true;
463→  }
464→
465→  return false;
466→}
