225→export async function handleEpics(
226→  req: IncomingMessage,
227→  res: ServerResponse,
228→  pathSegments: string[],
229→  queryParams: URLSearchParams,
230→  myAgentId: string | undefined,
231→): Promise<boolean> {
232→  if (listEpics.match(req.method, pathSegments)) {
233→    const parsed = await listEpics.parse(req, res, pathSegments, queryParams);
234→    if (!parsed) return true;
235→    const rawEpics = getEpics({
236→      status: (parsed.query.status as EpicStatus) || undefined,
237→      search: parsed.query.search || undefined,
238→      leadAgentId: parsed.query.leadAgentId || undefined,
239→    });
240→    const epics = rawEpics.map((e) => getEpicWithProgress(e.id) ?? e);
241→    json(res, { epics, total: epics.length });
242→    return true;
243→  }
244→
245→  if (createEpicRoute.match(req.method, pathSegments)) {
246→    const parsed = await createEpicRoute.parse(req, res, pathSegments, queryParams);
247→    if (!parsed) return true;
248→
249→    try {
250→      const epic = createEpic({
251→        ...parsed.body,
252→        createdByAgentId: myAgentId || undefined,
253→      });
254→      json(res, epic, 201);
255→    } catch (_error) {
256→      jsonError(res, "Failed to create epic", 500);
257→    }
258→    return true;
259→  }
260→
261→  if (getEpic.match(req.method, pathSegments)) {
262→    const parsed = await getEpic.parse(req, res, pathSegments, queryParams);
263→    if (!parsed) return true;
264→    const epic = getEpicWithProgress(parsed.params.id);
265→
266→    if (!epic) {
267→      jsonError(res, "Epic not found", 404);
268→      return true;
269→    }
270→
271→    const tasks = getTasksByEpicId(parsed.params.id);
272→    json(res, { ...epic, tasks });
273→    return true;
274→  }
275→
276→  if (updateEpicRoute.match(req.method, pathSegments)) {
277→    const parsed = await updateEpicRoute.parse(req, res, pathSegments, queryParams);
278→    if (!parsed) return true;
279→    const epic = updateEpic(parsed.params.id, parsed.body as Record<string, unknown>);
280→    if (!epic) {
281→      jsonError(res, "Epic not found", 404);
282→      return true;
283→    }
284→    json(res, epic);
285→    return true;
286→  }
287→
288→  if (deleteEpicRoute.match(req.method, pathSegments)) {
289→    const parsed = await deleteEpicRoute.parse(req, res, pathSegments, queryParams);
290→    if (!parsed) return true;
291→    const deleted = deleteEpic(parsed.params.id);
292→    if (!deleted) {
293→      jsonError(res, "Epic not found", 404);
294→      return true;
295→    }
296→    json(res, { success: true });
297→    return true;
298→  }
299→
300→  if (addTaskToEpic.match(req.method, pathSegments)) {
301→    const parsed = await addTaskToEpic.parse(req, res, pathSegments, queryParams);
302→    if (!parsed) return true;
303→    const epic = getEpicById(parsed.params.id);
304→
305→    if (!epic) {
306→      jsonError(res, "Epic not found", 404);
307→      return true;
308→    }
309→
310→    // If taskId provided, assign existing task
311→    if (parsed.body.taskId) {
312→      const task = assignTaskToEpic(parsed.body.taskId, parsed.params.id);
313→      if (!task) {
314→        jsonError(res, "Task not found", 404);
315→        return true;
316→      }
317→      json(res, task);
318→      return true;
319→    }
320→
321→    // Otherwise create new task in this epic
322→    if (!parsed.body.task) {
323→      jsonError(res, "Missing task description or taskId", 400);
324→      return true;
325→    }
326→
327→    try {
328→      const task = createTaskExtended(parsed.body.task, {
329→        ...parsed.body,
330→        epicId: parsed.params.id,
331→        creatorAgentId: myAgentId || undefined,
332→        tags: [...(parsed.body.tags || []), `epic:${epic.name}`],
333→        source: "api",
334→      });
335→      json(res, task, 201);
336→    } catch (_error) {
337→      jsonError(res, "Failed to create task", 500);
338→    }
339→    return true;
340→  }
341→
342→  if (listChannels.match(req.method, pathSegments)) {
343→    const channels = getAllChannels();
344→    json(res, { channels });
345→    return true;
346→  }
347→
348→  if (createChannelRoute.match(req.method, pathSegments)) {
349→    const parsed = await createChannelRoute.parse(req, res, pathSegments, queryParams);
350→    if (!parsed) return true;
351→
352→    const existing = getChannelByName(parsed.body.name);
353→    if (existing) {
354→      jsonError(res, "Channel with this name already exists", 409);
355→      return true;
356→    }
357→
358→    try {
359→      const channel = createChannel(parsed.body.name, {
360→        description: parsed.body.description,
361→        type: parsed.body.type,
362→      });
363→      json(res, channel, 201);
364→    } catch (_error) {
365→      jsonError(res, "Failed to create channel", 500);
366→    }
367→    return true;
368→  }
369→
370→  if (deleteChannelRoute.match(req.method, pathSegments)) {
371→    const parsed = await deleteChannelRoute.parse(req, res, pathSegments, queryParams);
372→    if (!parsed) return true;
373→
374→    const GENERAL_CHANNEL_ID = "00000000-0000-4000-8000-000000000001";
375→    if (parsed.params.id === GENERAL_CHANNEL_ID) {
376→      jsonError(res, "Cannot delete the general channel", 400);
377→      return true;
378→    }
379→
380→    const channel = getChannelById(parsed.params.id);
381→    if (!channel) {
382→      jsonError(res, "Channel not found", 404);
383→      return true;
384→    }
385→
386→    const deleted = deleteChannel(parsed.params.id);
387→    if (!deleted) {
388→      jsonError(res, "Failed to delete channel", 500);
389→      return true;
390→    }
391→
392→    json(res, { success: true });
393→    return true;
394→  }
395→
396→  if (listChannelMessages.match(req.method, pathSegments)) {
397→    const parsed = await listChannelMessages.parse(req, res, pathSegments, queryParams);
398→    if (!parsed) return true;
399→
400→    const channel = getChannelById(parsed.params.id);
401→    if (!channel) {
402→      jsonError(res, "Channel not found", 404);
403→      return true;
404→    }
405→
406→    const limit = parsed.query.limit ?? 50;
407→    const messages = getChannelMessagesDb(parsed.params.id, {
408→      limit,
409→      since: parsed.query.since || undefined,
410→      before: parsed.query.before || undefined,
411→    });
412→    json(res, { messages });
413→    return true;
414→  }
415→
416→  if (getThreadMessages.match(req.method, pathSegments)) {
417→    const parsed = await getThreadMessages.parse(req, res, pathSegments, queryParams);
418→    if (!parsed) return true;
419→
420→    const channel = getChannelById(parsed.params.channelId);
421→    if (!channel) {
422→      jsonError(res, "Channel not found", 404);
423→      return true;
424→    }
425→
426→    const allMessages = getChannelMessagesDb(parsed.params.channelId, { limit: 1000 });
427→    const threadMessages = allMessages.filter((m) => m.replyToId === parsed.params.messageId);
428→    json(res, { messages: threadMessages });
429→    return true;
430→  }
431→
432→  if (postMessageRoute.match(req.method, pathSegments)) {
433→    const parsed = await postMessageRoute.parse(req, res, pathSegments, queryParams);
434→    if (!parsed) return true;
435→
436→    const channel = getChannelById(parsed.params.id);
437→    if (!channel) {
438→      jsonError(res, "Channel not found", 404);
439→      return true;
440→    }
441→
442→    const agentId = parsed.body.agentId || null;
443→    if (agentId) {
444→      const agent = getAgentById(agentId);
445→      if (!agent) {
446→        jsonError(res, "Invalid agentId", 400);
447→        return true;
448→      }
449→    }
450→
451→    const message = postMessage(parsed.params.id, agentId, parsed.body.content, {
452→      replyToId: parsed.body.replyToId,
453→      mentions: parsed.body.mentions,
454→    });
455→    json(res, message, 201);
456→    return true;
457→  }
458→
459→  return false;
460→}
