 1→import type { IncomingMessage, ServerResponse } from "node:http";
 2→import { getActiveTaskCount } from "../be/db";
 3→
 4→export function setCorsHeaders(res: ServerResponse) {
 5→  res.setHeader("Access-Control-Allow-Origin", "*");
 6→  res.setHeader("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE, OPTIONS");
 7→  res.setHeader("Access-Control-Allow-Headers", "*");
 8→  res.setHeader("Access-Control-Expose-Headers", "*");
 9→}
10→
11→export function parseQueryParams(url: string): URLSearchParams {
12→  const queryIndex = url.indexOf("?");
13→  if (queryIndex === -1) return new URLSearchParams();
14→  return new URLSearchParams(url.slice(queryIndex + 1));
15→}
16→
17→export function getPathSegments(url: string): string[] {
18→  const pathEnd = url.indexOf("?");
19→  const path = pathEnd === -1 ? url : url.slice(0, pathEnd);
20→  return path.split("/").filter(Boolean);
21→}
