23→/** Add capacity info to agent response */
24→export function agentWithCapacity<T extends { id: string; maxTasks?: number }>(
25→  agent: T,
26→): T & { capacity: { current: number; max: number; available: number } } {
27→  const activeCount = getActiveTaskCount(agent.id);
28→  const max = agent.maxTasks ?? 1;
29→  return {
30→    ...agent,
31→    capacity: {
32→      current: activeCount,
33→      max,
34→      available: Math.max(0, max - activeCount),
35→    },
36→  };
37→}
38→
39→/** Parse JSON body from incoming request */
40→export async function parseBody<T = unknown>(req: IncomingMessage): Promise<T> {
41→  const chunks: Buffer[] = [];
42→  for await (const chunk of req) {
43→    chunks.push(chunk as Buffer);
44→  }
45→  return JSON.parse(Buffer.concat(chunks).toString()) as T;
46→}
