48→/** Send JSON response */
49→export function json(res: ServerResponse, data: unknown, status = 200) {
50→  res.writeHead(status, { "Content-Type": "application/json" });
51→  res.end(JSON.stringify(data));
52→}
53→
54→/** Send error JSON response */
55→export function jsonError(res: ServerResponse, error: string, status = 400) {
56→  res.writeHead(status, { "Content-Type": "application/json" });
57→  res.end(JSON.stringify({ error }));
58→}
