60→/**
61→ * Match a route pattern against HTTP method and path segments.
62→ *
63→ * @param method - HTTP method from request (e.g. "GET", "POST")
64→ * @param pathSegments - URL path segments (e.g. ["api", "config", "resolved"])
65→ * @param expectedMethod - Expected HTTP method to match
66→ * @param pattern - Segment patterns: string for literal match, null for dynamic param (must be truthy)
67→ * @param exact - If true, ensures no extra trailing segments exist (default: false)
68→ */
69→export function matchRoute(
70→  method: string | undefined,
71→  pathSegments: string[],
72→  expectedMethod: string,
73→  pattern: readonly (string | null)[],
74→  exact = false,
75→): boolean {
76→  if (method !== expectedMethod) return false;
77→  for (let i = 0; i < pattern.length; i++) {
78→    const seg = pattern[i];
79→    if (seg === null) {
80→      if (!pathSegments[i]) return false;
81→    } else {
82→      if (pathSegments[i] !== seg) return false;
83→    }
84→  }
85→  if (exact && pathSegments[pattern.length]) return false;
86→  return true;
87→}
